let body = (msg.req && msg.req.body != null) ? msg.req.body : msg.payload;
if (typeof body === 'string') { try { body = JSON.parse(body); } catch(e) { body = {}; } }
if (typeof body !== 'object' || body === null) body = {};
const chargerId = body.chargerId != null ? String(body.chargerId) : '';
const online = Boolean(body.online);
const message = typeof body.message === 'string' ? body.message : (online ? 'Charger is online' : 'Charger is offline');
const id = 'n-' + Date.now() + '-' + Math.random().toString(36).slice(2);
const level = online ? 'success' : 'info';
const timestamp = body.timestamp != null ? Number(body.timestamp) : Date.now();

let list = global.get('chargerNotificationsList') || [];
list.push({ id, chargerId, online, message, level, createdAt: new Date(timestamp).toISOString() });
if (list.length > 200) list = list.slice(-200);
global.set('chargerNotificationsList', list);

msg.payload = { success: true, id };
msg.notification = { id, chargerId, online, message, level, timestamp };
msg.statusCode = 200;
return msg;

const n = msg.notification;
if (!n || !n.id) return null;
const created_at_ms = n.timestamp != null && Number.isFinite(n.timestamp) ? Number(n.timestamp) : Date.now();
const sql = "INSERT INTO ocpp_CSGO.charger_notifications (id, charger_id, online, message, level, created_at) VALUES (?, ?, ?, ?, ?, ?)";
msg.topic = sql;
msg.sql = sql;
msg.payload = [n.id, n.chargerId || '', n.online ? 1 : 0, n.message || '', n.level || 'info', created_at_ms];
return msg;

const q = (msg.req && msg.req.query) || {};
const userId = (q.userId != null && String(q.userId).trim() !== '') ? String(q.userId).trim() : null;
const sinceRaw = (q.since != null) ? String(q.since).trim() : '';
const sinceNum = sinceRaw !== '' && Number.isFinite(Number(sinceRaw)) ? Number(sinceRaw) : 0;

const selBase = "n.id, n.charger_id AS chargerId, n.online, n.message, n.level, n.created_at AS timestamp, DATE_FORMAT(FROM_UNIXTIME(n.created_at/1000), '%Y-%m-%d %H:%i:%s') AS createdAt";
const selWithRead = selBase + ", (r.read_at IS NOT NULL) AS \`read\`, DATE_FORMAT(FROM_UNIXTIME(r.read_at/1000), '%Y-%m-%d %H:%i:%s') AS readAt";

if (userId) {
  msg.topic = "SELECT " + selWithRead + " FROM ocpp_CSGO.charger_notifications n LEFT JOIN ocpp_CSGO.user_notification_read r ON r.notification_id = n.id AND r.user_id = ? WHERE n.created_at >= ? ORDER BY n.created_at DESC LIMIT 200";
  msg.payload = [userId, sinceNum];
} else {
  msg.topic = "SELECT " + selBase + " FROM ocpp_CSGO.charger_notifications n WHERE n.created_at >= ? ORDER BY n.created_at DESC LIMIT 200";
  msg.payload = [sinceNum];
}
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];
const data = rows.map(r => ({
  id: r.id,
  chargerId: r.chargerId,
  online: r.online === 1 || r.online === true,
  message: r.message,
  level: r.level,
  timestamp: r.timestamp,
  createdAt: r.createdAt || (r.timestamp != null ? new Date(r.timestamp).toISOString().slice(0,19).replace('T',' ') : null),
  read: r.read === 1 || r.read === true,
  readAt: r.readAt || null
}));
msg.payload = { success: true, data };
msg.statusCode = 200;
return msg;

let raw = (msg.req && msg.req.body != null) ? msg.req.body : msg.payload;
if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { raw = {}; } }
if (typeof raw !== 'object' || raw === null) raw = {};
const body = raw;
const notificationId = (body.notificationId || body.notification_id || '').toString().trim();
const userId = body.userId != null ? Number(body.userId) : (body.user_id != null ? Number(body.user_id) : NaN);
if (!notificationId || !Number.isFinite(userId)) {
  msg.statusCode = 400;
  msg.payload = { success: false, message: 'notificationId and userId required' };
  return msg;
}
const read_at_ms = Date.now();
msg.topic = "INSERT INTO ocpp_CSGO.user_notification_read (user_id, notification_id, read_at) VALUES (?, ?, ?) ON DUPLICATE KEY UPDATE read_at = VALUES(read_at)";
msg.payload = [userId, notificationId, read_at_ms];
return msg;

msg.payload = { success: true, message: 'marked as read' };
msg.statusCode = 200;
return msg;

let raw = (msg.req && msg.req.body != null) ? msg.req.body : msg.payload;
if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { raw = {}; } }
if (typeof raw !== 'object' || raw === null) raw = {};
const body = raw;
const userId = body.userId != null ? Number(body.userId) : (body.user_id != null ? Number(body.user_id) : NaN);
if (!Number.isFinite(userId)) {
  msg.statusCode = 400;
  msg.payload = { success: false, message: 'userId required' };
  return msg;
}
const read_at_ms = Date.now();
msg.topic = "INSERT INTO ocpp_CSGO.user_notification_read (user_id, notification_id, read_at) SELECT ?, n.id, ? FROM ocpp_CSGO.charger_notifications n ORDER BY n.created_at DESC LIMIT 1000 ON DUPLICATE KEY UPDATE read_at = VALUES(read_at)";
msg.payload = [userId, read_at_ms];
return msg;

msg.payload = { success: true };
msg.statusCode = 200;
return msg;

const errMsg = msg.error && msg.error.message ? msg.error.message : (typeof msg.payload === 'string' ? msg.payload : 'Database or flow error');
const source = msg.error && msg.error.source ? msg.error.source : 'unknown';
msg.statusCode = 500;
msg.payload = { success: false, message: errMsg, _debug: { source } };
return msg;
